import clsx from 'clsx';
import { isNil } from 'lodash-es';
import type { PropsWithChildren } from 'react';

import { ChartOverlaysElevation } from '../../../constants.js';
import { plotLayout } from '../../chart-grid/ChartGrid.sty.js';
import { HorizontalCrosshair } from '../../crosshair/HorizontalCrosshair.js';
import { VerticalCrosshair } from '../../crosshair/VerticalCrosshair.js';
import { interactionsOverlay } from '../../interactions-overlay/InteractionsOverlay.sty.js';
import { useOverlay } from '../contexts/OverlayContext.js';
import { useTooltip } from '../contexts/TooltipContext.js';
import { useSelector, useTooltipSnapshot } from '../selectors.js';
import type { Data } from '../types.js';
import { useTooltipReducer } from '../useTooltipReducer.js';
import { isOwnEvent } from '../utils.js';

export const DummyInteractionsOverlay = (
  props: PropsWithChildren<{
    getData: () => Data;
  }>,
) => {
  const dispatch = useTooltipReducer();
  const tooltip = useTooltip();
  const overlay = useOverlay();

  return (
    <div
      role="none"
      ref={overlay.overlayRef}
      className={interactionsOverlay}
      onPointerMove={(event) =>
        isOwnEvent(event) &&
        dispatch({
          type: 'SET_POSITION',
          payload: {
            data: props.getData(),
            absoluteX: Math.round(event.clientX),
            absoluteY: Math.round(event.clientY),
          },
        })()
      }
      onPointerLeave={dispatch({ type: 'SET_OUT_BOUNDS' })}
      onClick={(event) => {
        if (!isOwnEvent(event)) {
          return;
        }
        if (tooltip.getState().pinned) {
          dispatch({
            type: 'SET_PINNED',
            payload: {
              pinned: false,
              data: {
                geometry: 'none',
                series: undefined,
                header1: undefined,
                subheader: undefined,
              },
            },
          })();
        } else {
          dispatch({
            type: 'SET_PINNED',
            payload: {
              pinned: true,
              data: props.getData(),
              absoluteX: Math.round(event.clientX),
              absoluteY: Math.round(event.clientY),
            },
          })();
        }
      }}
      style={{
        background: '#E6E6FA',
        position: 'absolute',
        width: '98%',
        height: '98%',
        top: '1%',
        left: '1%',
      }}
    >
      <Crosshair />
      {props.children}
    </div>
  );
};

const Crosshair = () => {
  const overlay = useOverlay();
  useSelector(
    ({ absoluteX, absoluteY, pinned }) => `${absoluteX}-${absoluteY}-${pinned}`,
  );
  const { relativeX, relativeY, pinned } = useTooltipSnapshot();
  const bounds = overlay.getBounds();

  if (isNil(bounds && relativeX && relativeY)) {
    return null;
  }

  return (
    <svg
      className={clsx(
        plotLayout,
        {
          overflow: 'visible',
          cursor: 'crosshair',
          zIndex: ChartOverlaysElevation.crosshair,
          pointerEvents: 'none',
        },
        interactionsOverlay,
      )}
    >
      <HorizontalCrosshair
        dashed={!pinned}
        y={relativeY as number}
        width={bounds?.width as number}
        height={bounds?.height as number}
        chartBounds={bounds}
        leftOffset={0}
        rightOffset={0}
      />
      <VerticalCrosshair
        dashed={!pinned}
        x={relativeX as number}
        height={bounds?.height as number}
        width={bounds?.width as number}
        chartBounds={bounds}
      />
    </svg>
  );
};
